use embedded_hal::digital::OutputPin;

fn blink<P: OutputPin>(led: &mut P, delay: &mut impl embedded_hal::delay::DelayNs) {
    led.set_high().unwrap();
    delay.delay_ms(500);
    led.set_low().unwrap();
    delay.delay_ms(500);
}
// Works on any chip that implements embedded-hal

